import type { MetadataRoute } from "next";

const origin = "https://www.scholarium.securedme.ca";

/** Static discovery roots; publication entries are generated by the XML route. */
export default function sitemap(): MetadataRoute.Sitemap {
  return [
    { url: origin, changeFrequency: "weekly", priority: 1 },
    { url: `${origin}/teach`, changeFrequency: "weekly", priority: 0.9 },
    { url: `${origin}/sitemap-publications.xml`, changeFrequency: "daily", priority: 0.8 },
  ];
}
